// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title AgentRegistry
 * @notice ERC-8004-inspired on-chain identity registry for AI trading agents.
 *         Each agent gets a unique ID, stores its metadata, and carries a
 *         trust score that evolves with trade outcomes.
 */
contract AgentRegistry {
    // ── Events ───────────────────────────────────────────────────────────────
    event AgentRegistered(
        uint256 indexed agentId,
        address indexed owner,
        string name,
        string strategy
    );
    event AgentDeactivated(uint256 indexed agentId);
    event TrustScoreUpdated(uint256 indexed agentId, uint256 newScore);

    // ── Data structures ───────────────────────────────────────────────────────
    struct Agent {
        uint256 id;
        address owner;
        string  name;
        string  strategy;   // "RSI", "MA_CROSSOVER", "SENTIMENT", "COMBINED"
        string  endpoint;   // off-chain API endpoint
        uint256 trustScore; // 0–100 (stored as integer, e.g. 75 = 75%)
        uint256 totalTrades;
        uint256 profitableTrades;
        int256  totalPnlBps; // basis points (1 bps = 0.01%)
        bool    active;
        uint256 registeredAt;
    }

    // ── State ─────────────────────────────────────────────────────────────────
    uint256 private _nextId = 1;
    mapping(uint256 => Agent) private _agents;
    mapping(address => uint256[]) private _ownerAgents;

    // Only the ReputationManager contract can update scores
    address public reputationManager;
    address public owner;

    modifier onlyOwner() {
        require(msg.sender == owner, "AgentRegistry: not owner");
        _;
    }

    modifier onlyReputationManager() {
        require(
            msg.sender == reputationManager || msg.sender == owner,
            "AgentRegistry: not reputation manager"
        );
        _;
    }

    constructor() {
        owner = msg.sender;
        reputationManager = msg.sender; // updated after ReputationManager deploy
    }

    // ── External functions ────────────────────────────────────────────────────

    /**
     * @notice Register a new AI trading agent.
     * @return agentId The unique on-chain identifier.
     */
    function registerAgent(
        string calldata name,
        string calldata strategy,
        string calldata endpoint
    ) external returns (uint256 agentId) {
        require(bytes(name).length > 0, "AgentRegistry: name required");
        require(bytes(strategy).length > 0, "AgentRegistry: strategy required");

        agentId = _nextId++;

        _agents[agentId] = Agent({
            id:               agentId,
            owner:            msg.sender,
            name:             name,
            strategy:         strategy,
            endpoint:         endpoint,
            trustScore:       50,   // start at neutral
            totalTrades:      0,
            profitableTrades: 0,
            totalPnlBps:      0,
            active:           true,
            registeredAt:     block.timestamp
        });

        _ownerAgents[msg.sender].push(agentId);

        emit AgentRegistered(agentId, msg.sender, name, strategy);
    }

    /**
     * @notice Deactivate an agent (owner only).
     */
    function deactivateAgent(uint256 agentId) external {
        Agent storage agent = _agents[agentId];
        require(agent.owner == msg.sender, "AgentRegistry: not agent owner");
        require(agent.active, "AgentRegistry: already inactive");
        agent.active = false;
        emit AgentDeactivated(agentId);
    }

    /**
     * @notice Update trust score and trade stats after a trade outcome.
     *         Called by ReputationManager.
     */
    function updateReputation(
        uint256 agentId,
        bool profitable,
        int256 pnlBps
    ) external onlyReputationManager {
        Agent storage agent = _agents[agentId];
        require(agent.active, "AgentRegistry: agent not active");

        agent.totalTrades++;
        agent.totalPnlBps += pnlBps;

        if (profitable) {
            agent.profitableTrades++;
            // Increase trust score (max 100)
            agent.trustScore = agent.trustScore >= 98
                ? 100
                : agent.trustScore + 2;
        } else {
            // Decrease trust score (min 0)
            agent.trustScore = agent.trustScore <= 2
                ? 0
                : agent.trustScore - 2;  // smaller penalty than reward
        }

        emit TrustScoreUpdated(agentId, agent.trustScore);
    }

    // ── View functions ────────────────────────────────────────────────────────

    function getAgent(uint256 agentId)
        external
        view
        returns (
            string memory name,
            string memory strategy,
            address agentOwner,
            uint256 trustScore,
            bool active,
            uint256 totalTrades,
            uint256 profitableTrades
        )
    {
        Agent storage a = _agents[agentId];
        return (
            a.name,
            a.strategy,
            a.owner,
            a.trustScore,
            a.active,
            a.totalTrades,
            a.profitableTrades
        );
    }

    function getTrustScore(uint256 agentId) external view returns (uint256) {
        return _agents[agentId].trustScore;
    }

    function getAgentsByOwner(address agentOwner)
        external
        view
        returns (uint256[] memory)
    {
        return _ownerAgents[agentOwner];
    }

    function totalAgents() external view returns (uint256) {
        return _nextId - 1;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setReputationManager(address manager) external onlyOwner {
        reputationManager = manager;
    }
}

contracts/ReputationManager.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./AgentRegistry.sol";
import "./ValidationRegistry.sol";

/**
 * @title ReputationManager
 * @notice Orchestrates trust score updates by combining:
 *           - Trade PnL outcome
 *           - Confidence accuracy (did high-confidence trades actually profit?)
 *           - Validator consensus score (extensible for multi-validator setups)
 *
 *         This is the final step in the trust layer pipeline.
 */
contract ReputationManager {
    event ReputationUpdated(
        uint256 indexed agentId,
        uint256 newTrustScore,
        int256  scoreDelta,
        string  reason
    );

    struct ScoreUpdate {
        uint256 agentId;
        string  tradeId;
        bool    profitable;
        int256  pnlBps;
        uint256 confidence;
        uint256 timestamp;
    }

    AgentRegistry     public agentRegistry;
    ValidationRegistry public validationRegistry;
    address public owner;

    // Score delta bounds
    int256 public constant MAX_POSITIVE_DELTA = 5;
    int256 public constant MAX_NEGATIVE_DELTA = -3;

    mapping(uint256 => ScoreUpdate[]) public agentHistory;

    modifier onlyOwner() {
        require(msg.sender == owner, "ReputationManager: not owner");
        _;
    }

    constructor(address _registry, address _validationRegistry) {
        owner             = msg.sender;
        agentRegistry     = AgentRegistry(_registry);
        validationRegistry = ValidationRegistry(_validationRegistry);
    }

    /**
     * @notice Update an agent's reputation after a trade settles.
     * @param agentId    On-chain agent ID.
     * @param tradeId    Off-chain trade UUID (must exist in ValidationRegistry).
     * @param profitable Whether the trade was profitable.
     * @param pnlBps     PnL in basis points.
     */
    function updateReputation(
        uint256 agentId,
        string calldata tradeId,
        bool profitable,
        int256 pnlBps
    ) external onlyOwner {
        // Fetch confidence from on-chain proof
        (,, uint256 confidence,,,,, ) =
            validationRegistry.getValidation(tradeId);

        // Compute delta: high confidence + profitable = bigger reward
        int256 delta = _computeDelta(profitable, pnlBps, confidence);

        // Record outcome on ValidationRegistry
        validationRegistry.recordOutcome(tradeId, profitable, pnlBps);

        // Update trust score on AgentRegistry
        agentRegistry.updateReputation(agentId, profitable, pnlBps);

        // Store history
        agentHistory[agentId].push(ScoreUpdate({
            agentId:    agentId,
            tradeId:    tradeId,
            profitable: profitable,
            pnlBps:     pnlBps,
            confidence: confidence,
            timestamp:  block.timestamp
        }));

        uint256 newScore = agentRegistry.getTrustScore(agentId);
        string memory reason = profitable
            ? "Profitable trade - trust increased"
            : "Unprofitable trade - trust decreased";

        emit ReputationUpdated(agentId, newScore, delta, reason);
    }

    /**
     * @notice Compute score delta based on outcome + confidence accuracy.
     *
     * Logic:
     *   - Profitable + high confidence (>= 75): +5 (agent was right AND confident)
     *   - Profitable + medium confidence:       +3
     *   - Profitable + low confidence:          +1 (lucky)
     *   - Unprofitable + high confidence:       -3 (overconfident and wrong)
     *   - Unprofitable + low confidence:        -1 (uncertain and wrong, expected)
     */
    function _computeDelta(
        bool profitable,
        int256 pnlBps,
        uint256 confidence
    ) internal pure returns (int256 delta) {
        if (profitable) {
            if (confidence >= 75) delta = 5;
            else if (confidence >= 55) delta = 3;
            else delta = 1;
            // Bonus for exceptional returns
            if (pnlBps > 200) delta += 1; // >2% return
        } else {
            if (confidence >= 75) delta = -3; // overconfident wrong
            else if (confidence >= 55) delta = -2;
            else delta = -1;
        }

        // Clamp
        if (delta > MAX_POSITIVE_DELTA) delta = MAX_POSITIVE_DELTA;
        if (delta < MAX_NEGATIVE_DELTA) delta = MAX_NEGATIVE_DELTA;
    }

    // ── View ──────────────────────────────────────────────────────────────────

    function getAgentHistory(uint256 agentId)
        external
        view
        returns (ScoreUpdate[] memory)
    {
        return agentHistory[agentId];
    }

    function getTrustScore(uint256 agentId) external view returns (uint256) {
        return agentRegistry.getTrustScore(agentId);
    }
}

contracts/RiskRouter.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

import "./AgentRegistry.sol";

/**
 * @title RiskRouter
 * @notice On-chain risk gatekeeper for AI trading agents.
 *
 *         Before any trade executes, the RiskRouter:
 *         1. Verifies the EIP-712 signature from the agent's wallet
 *         2. Checks trade limits (single trade + daily loss)
 *         3. Verifies the token is in the allowed list
 *         4. Emits TradeApproved / TradeRejected for indexers
 *
 *         Trade execution itself happens off-chain (DEX router call)
 *         but all approvals are permanently recorded here.
 */
contract RiskRouter {
    // ── Events ────────────────────────────────────────────────────────────────
    event TradeApproved(
        uint256 indexed agentId,
        address indexed wallet,
        bytes32 tradeHash,
        string  tokenPair,
        string  action,
        uint256 amountUsd
    );
    event TradeRejected(
        uint256 indexed agentId,
        bytes32 tradeHash,
        string  reason
    );
    event TokenAllowlistUpdated(string token, bool allowed);
    event LimitsUpdated(uint256 maxSingleTradeUsd, uint256 maxDailyLossUsd);

    // ── Structs ───────────────────────────────────────────────────────────────
    struct TradeIntent {
        uint256 agentId;
        string  tokenPair;    // e.g. "ETH/USDC"
        string  action;       // "BUY" | "SELL"
        uint256 amountUsd;    // in USD cents to avoid decimals (e.g. 10000 = $100)
        uint256 confidence;   // 0-100
        string  reason;
        uint256 nonce;
        uint256 deadline;
    }

    struct DailyStats {
        uint256 date;         // block.timestamp / 86400
        uint256 totalLossUsd;
        uint256 tradeCount;
    }

    // ── State ─────────────────────────────────────────────────────────────────
    AgentRegistry public agentRegistry;
    address public owner;

    uint256 public maxSingleTradeUsd = 5_000 * 100;  // $5,000 in cents
    uint256 public maxDailyLossUsd   = 10_000 * 100; // $10,000 in cents
    uint256 public minConfidence      = 45;

    mapping(string => bool) public allowedTokens;
    mapping(uint256 => DailyStats) public agentDailyStats; // agentId → stats
    mapping(bytes32 => bool) public processedTrades;        // prevent replay
    mapping(uint256 => uint256) public agentNonces;

    // EIP-712 domain separator
    bytes32 public immutable DOMAIN_SEPARATOR;
    bytes32 public constant TRADE_TYPEHASH = keccak256(
        "TradeIntent(uint256 agentId,string tokenPair,string action,uint256 amountUsd,uint256 confidence,string reason,uint256 nonce,uint256 deadline)"
    );

    modifier onlyOwner() {
        require(msg.sender == owner, "RiskRouter: not owner");
        _;
    }

    constructor(address _agentRegistry) {
        owner = msg.sender;
        agentRegistry = AgentRegistry(_agentRegistry);

        // Seed allowlist
        allowedTokens["ETH"]   = true;
        allowedTokens["BTC"]   = true;
        allowedTokens["MATIC"] = true;
        allowedTokens["LINK"]  = true;
        allowedTokens["UNI"]   = true;
        allowedTokens["AAVE"]  = true;

        DOMAIN_SEPARATOR = keccak256(
            abi.encode(
                keccak256("EIP712Domain(string name,string version,uint256 chainId,address verifyingContract)"),
                keccak256(bytes("AITradingAgent")),
                keccak256(bytes("1")),
                block.chainid,
                address(this)
            )
        );
    }

    // ── Core: validate + approve a trade ─────────────────────────────────────

    /**
     * @notice Submit a signed trade intent for risk validation.
     * @param intent  The trade parameters.
     * @param v,r,s   EIP-712 signature from the agent wallet.
     * @return approved Whether the trade passed all risk checks.
     * @return tradeHash Unique hash for this trade (used for replay protection).
     */
    function submitTrade(
        TradeIntent calldata intent,
        uint8  v,
        bytes32 r,
        bytes32 s
    ) external returns (bool approved, bytes32 tradeHash) {
        // ── Deadline check ────────────────────────────────────────────────────
        require(block.timestamp <= intent.deadline, "RiskRouter: trade expired");

        // ── Nonce / replay protection ─────────────────────────────────────────
        require(
            intent.nonce == agentNonces[intent.agentId],
            "RiskRouter: invalid nonce"
        );

        // ── Compute and check trade hash ──────────────────────────────────────
        tradeHash = _hashTrade(intent);
        require(!processedTrades[tradeHash], "RiskRouter: already processed");

        // ── Signature verification (EIP-712) ──────────────────────────────────
        address signer = _recoverSigner(tradeHash, v, r, s);
        // (In production, compare signer to agent owner from AgentRegistry)
        require(signer != address(0), "RiskRouter: invalid signature");

        // ── Risk checks ───────────────────────────────────────────────────────
        (bool passed, string memory rejectReason) = _runRiskChecks(intent);

        processedTrades[tradeHash] = true;
        agentNonces[intent.agentId]++;

        if (passed) {
            _updateDailyStats(intent);
            emit TradeApproved(
                intent.agentId,
                signer,
                tradeHash,
                intent.tokenPair,
                intent.action,
                intent.amountUsd
            );
            return (true, tradeHash);
        } else {
            emit TradeRejected(intent.agentId, tradeHash, rejectReason);
            return (false, tradeHash);
        }
    }

    // ── Internal helpers ──────────────────────────────────────────────────────

    function _runRiskChecks(TradeIntent calldata intent)
        internal
        view
        returns (bool, string memory)
    {
        // 1. Confidence threshold
        if (intent.confidence < minConfidence) {
            return (false, "Confidence below minimum");
        }

        // 2. Single trade limit
        if (intent.amountUsd > maxSingleTradeUsd) {
            return (false, "Exceeds single trade limit");
        }

        // 3. Token allowlist (extract base token from "ETH/USDC" → "ETH")
        string memory baseToken = _extractBaseToken(intent.tokenPair);
        if (!allowedTokens[baseToken]) {
            return (false, "Token not in allowlist");
        }

        // 4. Daily loss limit
        DailyStats storage stats = agentDailyStats[intent.agentId];
        uint256 today = block.timestamp / 86400;
        if (stats.date == today && stats.totalLossUsd >= maxDailyLossUsd) {
            return (false, "Daily loss limit reached");
        }

        // 5. Agent must be active
        (,,,, bool active,,) = agentRegistry.getAgent(intent.agentId);
        if (!active) {
            return (false, "Agent not active");
        }

        return (true, "");
    }

    function _updateDailyStats(TradeIntent calldata intent) internal {
        uint256 today = block.timestamp / 86400;
        DailyStats storage stats = agentDailyStats[intent.agentId];
        if (stats.date != today) {
            stats.date = today;
            stats.totalLossUsd = 0;
            stats.tradeCount = 0;
        }
        stats.tradeCount++;
    }

    function _hashTrade(TradeIntent calldata intent)
        internal
        view
        returns (bytes32)
    {
        bytes32 structHash = keccak256(
            abi.encode(
                TRADE_TYPEHASH,
                intent.agentId,
                keccak256(bytes(intent.tokenPair)),
                keccak256(bytes(intent.action)),
                intent.amountUsd,
                intent.confidence,
                keccak256(bytes(intent.reason)),
                intent.nonce,
                intent.deadline
            )
        );
        return keccak256(abi.encodePacked("\x19\x01", DOMAIN_SEPARATOR, structHash));
    }

    function _recoverSigner(bytes32 hash, uint8 v, bytes32 r, bytes32 s)
        internal
        pure
        returns (address)
    {
        return ecrecover(hash, v, r, s);
    }

    function _extractBaseToken(string calldata pair)
        internal
        pure
        returns (string memory)
    {
        bytes memory b = bytes(pair);
        uint256 slashIdx = 0;
        for (uint256 i = 0; i < b.length; i++) {
            if (b[i] == "/") { slashIdx = i; break; }
        }
        if (slashIdx == 0) return pair;
        bytes memory base = new bytes(slashIdx);
        for (uint256 i = 0; i < slashIdx; i++) base[i] = b[i];
        return string(base);
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setLimits(uint256 maxSingle, uint256 maxDaily) external onlyOwner {
        maxSingleTradeUsd = maxSingle;
        maxDailyLossUsd   = maxDaily;
        emit LimitsUpdated(maxSingle, maxDaily);
    }

    function setTokenAllowed(string calldata token, bool allowed) external onlyOwner {
        allowedTokens[token] = allowed;
        emit TokenAllowlistUpdated(token, allowed);
    }

    function setMinConfidence(uint256 threshold) external onlyOwner {
        minConfidence = threshold;
    }

    // ── View ──────────────────────────────────────────────────────────────────

    function getAgentNonce(uint256 agentId) external view returns (uint256) {
        return agentNonces[agentId];
    }

    function isTradeProcessed(bytes32 tradeHash) external view returns (bool) {
        return processedTrades[tradeHash];
    }
}

contracts/ValidationRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.24;

/**
 * @title ValidationRegistry
 * @notice Immutable on-chain log of AI trading decisions.
 *
 *         Every trade that passes risk checks stores:
 *         - Agent ID
 *         - Trade ID (off-chain UUID)
 *         - AI reasoning summary
 *         - Confidence score
 *         - Risk check result
 *         - Timestamp
 *
 *         This creates a tamper-proof audit trail for the trust layer.
 */
contract ValidationRegistry {
    // ── Events ────────────────────────────────────────────────────────────────
    event ValidationStored(
        uint256 indexed agentId,
        string  indexed tradeId,
        uint256 confidence,
        string  riskCheck,
        uint256 timestamp
    );
    event OutcomeRecorded(
        string  indexed tradeId,
        bool    profitable,
        int256  pnlBps
    );

    // ── Structs ───────────────────────────────────────────────────────────────
    struct Validation {
        uint256 agentId;
        string  tradeId;
        string  reason;        // AI explanation (truncated to 256 chars)
        uint256 confidence;    // 0-100
        string  riskCheck;     // "passed" | "failed"
        uint256 timestamp;
        bool    outcomeRecorded;
        bool    profitable;
        int256  pnlBps;
    }

    // ── State ─────────────────────────────────────────────────────────────────
    mapping(string => Validation) private _validations;  // tradeId → Validation
    mapping(uint256 => string[])  private _agentTrades;  // agentId → tradeIds[]

    uint256 public totalValidations;
    address public owner;
    address public authorizedCaller; // backend service wallet

    modifier onlyAuthorized() {
        require(
            msg.sender == owner || msg.sender == authorizedCaller,
            "ValidationRegistry: not authorized"
        );
        _;
    }

    modifier onlyOwner() {
        require(msg.sender == owner, "ValidationRegistry: not owner");
        _;
    }

    constructor() {
        owner = msg.sender;
        authorizedCaller = msg.sender;
    }

    // ── Write functions ───────────────────────────────────────────────────────

    /**
     * @notice Store AI decision proof before trade execution.
     * @param agentId    On-chain agent identifier.
     * @param tradeId    Off-chain UUID for cross-referencing.
     * @param reason     AI reasoning string (capped at 256 bytes on-chain).
     * @param confidence AI confidence score (0-100).
     * @param riskCheck  Result of risk validation ("passed" / "failed").
     */
    function storeValidation(
        uint256 agentId,
        string calldata tradeId,
        string calldata reason,
        uint256 confidence,
        string calldata riskCheck
    ) external onlyAuthorized {
        require(bytes(tradeId).length > 0, "ValidationRegistry: tradeId required");
        require(
            bytes(_validations[tradeId].tradeId).length == 0,
            "ValidationRegistry: tradeId already stored"
        );
        require(confidence <= 100, "ValidationRegistry: invalid confidence");

        // Truncate reason to 256 chars for gas efficiency
        string memory truncatedReason = _truncate(reason, 256);

        _validations[tradeId] = Validation({
            agentId:         agentId,
            tradeId:         tradeId,
            reason:          truncatedReason,
            confidence:      confidence,
            riskCheck:       riskCheck,
            timestamp:       block.timestamp,
            outcomeRecorded: false,
            profitable:      false,
            pnlBps:          0
        });

        _agentTrades[agentId].push(tradeId);
        totalValidations++;

        emit ValidationStored(agentId, tradeId, confidence, riskCheck, block.timestamp);
    }

    /**
     * @notice Record the trade outcome after settlement.
     * @param tradeId    Off-chain UUID.
     * @param profitable Whether the trade made a profit.
     * @param pnlBps     PnL in basis points (can be negative).
     */
    function recordOutcome(
        string calldata tradeId,
        bool profitable,
        int256 pnlBps
    ) external onlyAuthorized {
        Validation storage v = _validations[tradeId];
        require(bytes(v.tradeId).length > 0, "ValidationRegistry: trade not found");
        require(!v.outcomeRecorded, "ValidationRegistry: outcome already recorded");

        v.outcomeRecorded = true;
        v.profitable      = profitable;
        v.pnlBps          = pnlBps;

        emit OutcomeRecorded(tradeId, profitable, pnlBps);
    }

    // ── View functions ────────────────────────────────────────────────────────

    function getValidation(string calldata tradeId)
        external
        view
        returns (
            uint256 agentId,
            string memory reason,
            uint256 confidence,
            string memory riskCheck,
            uint256 timestamp,
            bool outcomeRecorded,
            bool profitable,
            int256 pnlBps
        )
    {
        Validation storage v = _validations[tradeId];
        return (
            v.agentId,
            v.reason,
            v.confidence,
            v.riskCheck,
            v.timestamp,
            v.outcomeRecorded,
            v.profitable,
            v.pnlBps
        );
    }

    function getAgentTradeIds(uint256 agentId)
        external
        view
        returns (string[] memory)
    {
        return _agentTrades[agentId];
    }

    function getAgentTradeCount(uint256 agentId) external view returns (uint256) {
        return _agentTrades[agentId].length;
    }

    // ── Admin ─────────────────────────────────────────────────────────────────

    function setAuthorizedCaller(address caller) external onlyOwner {
        authorizedCaller = caller;
    }

    // ── Helpers ───────────────────────────────────────────────────────────────

    function _truncate(string calldata s, uint256 maxLen)
        internal
        pure
        returns (string memory)
    {
        bytes calldata b = bytes(s);
        if (b.length <= maxLen) return s;
        bytes memory out = new bytes(maxLen);
        for (uint256 i = 0; i < maxLen; i++) out[i] = b[i];
        return string(out);
    }
}

